/**
 * EntityBrowser Component
 * Tabbed interface for browsing and editing all entity types
 */

import React, { useState } from 'react';
import useWorldBuilderStore from '../store/store';
import EntityList from './EntityList';
import MobileEditor from './MobileEditor';
import ObjectEditor from './ObjectEditor';
import ResetList from './ResetList';
import '../styles/EntityBrowser.css';

export default function EntityBrowser() {
  const [activeTab, setActiveTab] = useState('mobiles');
  const [showNewForm, setShowNewForm] = useState(false);

  const {
    currentAreaData,
    selectedMobile,
    selectedObject,
    selectedReset,
    selectMobile,
    selectObject,
    createMobile,
    updateMobile,
    deleteMobile,
    createObject,
    updateObject,
    deleteObject,
    message,
    error,
  } = useWorldBuilderStore();

  if (!currentAreaData) {
    return (
      <div className="entity-browser">
        <p className="no-area-message">Load an area to browse entities</p>
      </div>
    );
  }

  const handleMobileSave = async (formData) => {
    if (selectedMobile) {
      await updateMobile(selectedMobile, formData);
    } else {
      await createMobile(formData);
    }
    setShowNewForm(false);
  };

  const handleObjectSave = async (formData) => {
    if (selectedObject) {
      await updateObject(selectedObject, formData);
    } else {
      await createObject(formData);
    }
    setShowNewForm(false);
  };

  const currentMobile = selectedMobile
    ? currentAreaData.mobiles.find(m => m.vnum === selectedMobile)
    : null;

  const currentObject = selectedObject
    ? currentAreaData.objects.find(o => o.vnum === selectedObject)
    : null;

  return (
    <div className="entity-browser">
      {(message || error) && (
        <div className={`browser-message ${error ? 'error' : 'success'}`}>
          {error || message}
        </div>
      )}

      <div className="browser-tabs">
        <button
          className={`tab ${activeTab === 'mobiles' ? 'active' : ''}`}
          onClick={() => {
            setActiveTab('mobiles');
            setShowNewForm(false);
          }}
        >
          Mobiles ({currentAreaData.mobiles?.length || 0})
        </button>
        <button
          className={`tab ${activeTab === 'objects' ? 'active' : ''}`}
          onClick={() => {
            setActiveTab('objects');
            setShowNewForm(false);
          }}
        >
          Objects ({currentAreaData.objects?.length || 0})
        </button>
        <button
          className={`tab ${activeTab === 'resets' ? 'active' : ''}`}
          onClick={() => {
            setActiveTab('resets');
            setShowNewForm(false);
          }}
        >
          Resets ({currentAreaData.resets?.length || 0})
        </button>
      </div>

      <div className="browser-content">
        {activeTab === 'mobiles' && (
          <div className="browser-panel">
            <EntityList
              entities={currentAreaData.mobiles || []}
              entityType="Mobiles"
              selected={selectedMobile}
              onSelect={selectMobile}
              onCreateNew={() => setShowNewForm(true)}
              onDelete={deleteMobile}
            />
            <div className="browser-editor">
              {showNewForm ? (
                <MobileEditor
                  mobile={null}
                  onSave={handleMobileSave}
                  onCancel={() => setShowNewForm(false)}
                />
              ) : (
                <MobileEditor
                  mobile={currentMobile}
                  onSave={handleMobileSave}
                  onCancel={() => setShowNewForm(false)}
                />
              )}
            </div>
          </div>
        )}

        {activeTab === 'objects' && (
          <div className="browser-panel">
            <EntityList
              entities={currentAreaData.objects || []}
              entityType="Objects"
              selected={selectedObject}
              onSelect={selectObject}
              onCreateNew={() => setShowNewForm(true)}
              onDelete={deleteObject}
            />
            <div className="browser-editor">
              {showNewForm ? (
                <ObjectEditor
                  object={null}
                  onSave={handleObjectSave}
                  onCancel={() => setShowNewForm(false)}
                />
              ) : (
                <ObjectEditor
                  object={currentObject}
                  onSave={handleObjectSave}
                  onCancel={() => setShowNewForm(false)}
                />
              )}
            </div>
          </div>
        )}

        {activeTab === 'resets' && (
          <div className="browser-panel">
            <ResetList
              resets={currentAreaData.resets || []}
              selected={selectedReset}
              onSelect={() => {}}
              onCreateNew={() => {}}
              onDelete={() => {}}
            />
            <div className="browser-editor">
              <div className="reset-editor-placeholder">
                <p>Reset editor coming in Sprint 4</p>
                <p style={{ fontSize: '0.9em', color: '#999' }}>
                  Currently supports viewing reset commands and their parameters
                </p>
              </div>
            </div>
          </div>
        )}
      </div>
    </div>
  );
}
